INSERT INTO app_updates (title, description, update_type, version, is_active, created_at) VALUES
('Super Admin Role', 'Introduced a super admin role with the ability to view and manage all users'' SIM card information. Super admins can now access a dedicated admin page to oversee the entire system.', 'feature', '3.5.0', true, '2025-12-08 00:00:00+00'),
('Admin User Management Page', 'Added a comprehensive admin page for super admins to manage users and their SIM cards. Includes user search, SIM card viewing, and the ability to swap SIM ownership between accounts with full audit tracking.', 'feature', '3.4.0', true, '2025-12-07 00:00:00+00'),
('SIM Card Ownership History', 'Implemented complete audit trail for SIM card ownership changes. Every time a SIM card is transferred between users, the system now records who owned it previously, creating a full accountability history.', 'feature', '3.3.0', true, '2025-12-06 00:00:00+00'),
('Sideways Living Partnership', 'Integrated Sideways Living branding into the application header, along with a refreshed color palette inspired by the partnership. The new design features warm orange-red, deep purple, and teal accent colors.', 'improvement', '3.2.1', true, '2025-12-05 00:00:00+00'),
('Enhanced MFA Security', 'Upgraded MFA secret encryption to use unique per-user salts instead of a fixed salt. This provides stronger cryptographic protection, ensuring each user''s encrypted secrets are independently secured.', 'security', '3.6.0', true, '2025-12-09 00:00:00+00'),
('Secure Password Hashing', 'Upgraded account password storage to use industry-standard bcrypt hashing. Passwords are now securely hashed with a cost factor of 12, providing robust protection against brute-force attacks.', 'security', '3.7.0', true, '2025-12-10 00:00:00+00'),
('Server-Side Passkey Verification', 'Moved passkey authentication verification to a secure server-side edge function. This ensures cryptographic signature verification happens on the server, eliminating client-side security vulnerabilities.', 'security', '3.6.1', true, '2025-12-09 12:00:00+00');